protected void createJournalLine(Common _salesParmLine)
{
    SalesParmLine salesParmLine = _salesParmLine as SalesParmLine;        

    next createJournalLine(salesParmLine);

    if(InventParameters::find().ETGEnableQualityParameter == NoYes::Yes)
    {
        if(custInvoiceTrans.recid)
        {
            ETGSalesShipmentCashew      ETGSalesShipmentCashew;

            ETGSalesShipmentCashew.clear();
            ETGSalesShipmentCashew.initValue();
            ETGSalesShipmentCashew.RefInvoiceId =custInvoiceTrans.invoiceid;
            ETGSalesShipmentCashew.CustInvoiceTrans = custInvoiceTrans.recid;
            ETGSalesShipmentCashew.ACFContractNUMBER = salesParmLine.ETGACFContractNUMBER;
            ETGSalesShipmentCashew.OutturnNutCount = salesParmLine.ETGOutturnNutCount;
            ETGSalesShipmentCashew.SHIPMENT = salesParmLine.ETGSHIPMENT;
            ETGSalesShipmentCashew.PORTOFDischarge = salesParmLine.ETGPORTOFDischarge;
            ETGSalesShipmentCashew.ContractQuantity = salesParmLine.ETGContractQuantity;
            ETGSalesShipmentCashew.NumberofContainer = salesParmLine.ETGNumberofContainer;
            ETGSalesShipmentCashew.Bags = salesParmLine.ETGBags;
            ETGSalesShipmentCashew.NetWeight = salesParmLine.ETGNetWeight;
            ETGSalesShipmentCashew.PKL = salesParmLine.ETGPKL;
            ETGSalesShipmentCashew.DeclarationNumber = salesParmLine.ETGDeclarationNumber;
            ETGSalesShipmentCashew.LINE = salesParmLine.ETGLINE;
            ETGSalesShipmentCashew.Warehouse = salesParmLine.ETGWarehouse;
            ETGSalesShipmentCashew.Vessel = salesParmLine.ETGVessel;
            ETGSalesShipmentCashew.GrossWeight = salesParmLine.ETGGrossWeight;
            ETGSalesShipmentCashew.ContractNumber = salesParmLine.ETGContractNumber;
            ETGSalesShipmentCashew.LocalContractNumber = salesParmLine.ETGLocalContractNumber;
            ETGSalesShipmentCashew.HBLNumber = salesParmLine.ETGHBLNumber;
            ETGSalesShipmentCashew.ETGBulk = salesParmLine.ETGBulk;
            ETGSalesShipmentCashew.ETGNoDeclaration = salesParmLine.ETGNoDeclaration;
            ETGSalesShipmentCashew.ETGPacking = salesParmLine.ETGPacking;
            ETGSalesShipmentCashew.ETGCrop = salesParmLine.ETGCrop;
            ETGSalesShipmentCashew.insert();

            ETGSalesShipmentCocoa       ETGSalesShipmentCocoa;
            ETGSalesShipmentCocoa.clear();
            ETGSalesShipmentCocoa.initValue();
            ETGSalesShipmentCocoa.RefInvoiceId = custInvoiceTrans.invoiceid;
            ETGSalesShipmentCocoa.CustInvoiceTrans =  custInvoiceTrans.recid;
            ETGSalesShipmentCocoa.ETGReferences = salesParmLine.ETGReferences;
            ETGSalesShipmentCocoa.CCCReferences = salesParmLine.ETGCCCReferences;
            ETGSalesShipmentCocoa.ACFContractNumber = salesParmLine.ETGACFContractNumber;
            ETGSalesShipmentCocoa.ShippingPeriod = salesParmLine.ETGShippingPeriod;
            ETGSalesShipmentCocoa.Customer = salesParmLine.ETGCustomer;
            ETGSalesShipmentCocoa.Exporter = salesParmLine.ETGExporter;
            ETGSalesShipmentCocoa.LotsNumber = salesParmLine.ETGLotsNumber;
            ETGSalesShipmentCocoa.TheoriticalQuantity = salesParmLine.ETGTheoriticalQuantity;
            ETGSalesShipmentCocoa.PalletsLotWeight = salesParmLine.ETGPalletsLotWeight;
            ETGSalesShipmentCocoa.BillofLadingWeight = salesParmLine.ETGBillofLadingWeight;
            ETGSalesShipmentCocoa.WeightLoss = salesParmLine.ETGWeightLoss;
            ETGSalesShipmentCocoa.WeightLossPer = salesParmLine.ETGWeightLossPer;
            ETGSalesShipmentCocoa.TransitOrder = salesParmLine.ETGTransitOrder;
            ETGSalesShipmentCocoa.BVApplied = salesParmLine.ETGBVApplied;
            ETGSalesShipmentCocoa.BVReceived = salesParmLine.ETGBVReceived;
            ETGSalesShipmentCocoa.BVStatus = salesParmLine.ETGBVStatus;
            ETGSalesShipmentCocoa.Vessel = salesParmLine.ETGVesselCocoa;
            ETGSalesShipmentCocoa.ETGBulk = salesParmLine.ETGBulk;
            ETGSalesShipmentCocoa.ETGNoDeclaration = salesParmLine.ETGNoDeclaration;
            ETGSalesShipmentCocoa.ETGPacking = salesParmLine.ETGPacking;
            ETGSalesShipmentCocoa.ETGCrop = salesParmLine.ETGCrop;
            ETGSalesShipmentCocoa.insert();

        }
    }
}
